// Expression: n = 5
// Expression: inputstepper(at(1,1), n, 1, 20, 1)
// Expression: S = p5sheet(at(2, 1), view(25, 7))
// Script:
function setup() { canvas(); }
function draw() {
  background(255);
  let n = fields.n != undefined ? fields.n : 5;
  fill(0);
  noStroke();
  textSize(20);
  text('n = ' + n, 50, 50);
  for (let i = 0; i < n; i++) {
    fill('steelblue');
    rect(50 + i * 40, 80, 30, 30);
  }
}

let stepper;
function setup() {
  canvas();
  frameRate(30);
  stepper = phaseStepper(3);
}
function mousePressed() { stepper.handleClick(); }
function draw() {
  background(255);
  let t1 = stepper.phaseT(1);
  let t2 = stepper.phaseT(2);
  let t3 = stepper.phaseT(3);
  // Draw progressively based on phase progress
  if (t1 > 0) {
    stroke(0); strokeWeight(2);
    line(50, 200, lerp(50, 350, t1), 200);
  }
  if (t2 > 0) {
    line(350, 200, 350, lerp(200, 50, t2));
  }
  if (t3 > 0) {
    line(350, 50, lerp(350, 50, t3), lerp(50, 200, t3));
  }
  stepper.draw();
}

function setup() {
  canvas();
  let b = bridge();
  b.noAnimate();
  b.g2d('G', { row: 0, col: 0, size: 20, type: 'geometry' });
  b.point('P1', { graph: 'G', x: 2, y: 3 });
  b.point('P2', { graph: 'G', x: 5, y: 1 });
  b.line('L', { graph: 'G', x1: 2, y1: 3, x2: 5, y2: 1 });
}
